// Generated by OrchestKit Claude Plugin
// Created: 2026-06-07

/**
 * Headroom Store — Unit Tests (#2264).
 *
 * Targeted tests for the reversible-compression backing store: content-address
 * stability, dedup/skip-write, the GC TTL sweep, and pointer formatting.
 * The PII-before-stash invariant is enforced at the CALL site (the hook redacts
 * first); here we verify the store faithfully persists whatever it is handed and
 * that the hash is over the exact bytes given.
 */

import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { existsSync, mkdtempSync, mkdirSync, readFileSync, rmSync, statSync, utimesSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';

import {
  HASH_LEN,
  HEADROOM_DEFAULT_TTL_MS,
  getHeadroomDir,
  hashContent,
  stashPath,
  stashOriginal,
  buildPointer,
  gcHeadroom,
} from '../../lib/headroom-store.js';

describe('lib/headroom-store (#2264)', () => {
  let home: string;

  beforeEach(() => {
    home = mkdtempSync(join(tmpdir(), 'headroom-'));
  });

  afterEach(() => {
    try { rmSync(home, { recursive: true, force: true }); } catch { /* best-effort */ }
  });

  // ---- paths ----------------------------------------------------------------

  test('getHeadroomDir nests under the orchestkit state root', () => {
    expect(getHeadroomDir(home)).toBe(join(home, '.claude', 'state', 'orchestkit', 'headroom'));
  });

  test('stashPath is <dir>/<hash>.txt', () => {
    expect(stashPath('abc123def456', home)).toBe(join(getHeadroomDir(home), 'abc123def456.txt'));
  });

  // ---- hashing --------------------------------------------------------------

  test('hashContent is HASH_LEN hex chars and deterministic', () => {
    const h = hashContent('hello world');
    expect(h).toHaveLength(HASH_LEN);
    expect(h).toMatch(/^[0-9a-f]+$/);
    expect(hashContent('hello world')).toBe(h);
  });

  test('different content → different hash', () => {
    expect(hashContent('alpha')).not.toBe(hashContent('beta'));
  });

  // ---- stash + dedup --------------------------------------------------------

  test('stashOriginal writes the full original verbatim', () => {
    const text = 'line1\nline2\n'.repeat(500); // ~6KB
    const { hash, path, written } = stashOriginal(text, home);

    expect(written).toBe(true);
    expect(hash).toHaveLength(HASH_LEN);
    expect(existsSync(path)).toBe(true);
    expect(readFileSync(path, 'utf8')).toBe(text); // byte-for-byte, no truncation
  });

  test('stashing identical content twice dedups (skip-write)', () => {
    const text = 'dedupe me'.repeat(300);
    const first = stashOriginal(text, home);
    const mtime1 = statSync(first.path).mtimeMs;

    const second = stashOriginal(text, home);

    expect(second.hash).toBe(first.hash);
    expect(second.path).toBe(first.path);
    expect(second.written).toBe(false);          // dedup hit — no second write
    expect(statSync(second.path).mtimeMs).toBe(mtime1); // file untouched
  });

  test('the store persists whatever bytes it is given (redaction is the caller\'s job)', () => {
    // The hook redacts BEFORE calling. We assert the store does NOT redact —
    // i.e. it is the caller's contract to pass already-redacted text.
    const redacted = 'user [REDACTED_EMAIL] did a thing';
    const { path } = stashOriginal(redacted, home);
    expect(readFileSync(path, 'utf8')).toBe(redacted);
    expect(readFileSync(path, 'utf8')).not.toContain('@'); // sanity: caller redacted
  });

  // ---- pointer --------------------------------------------------------------

  test('buildPointer reports original, kept, and between counts', () => {
    const ptr = buildPointer({ originalLen: 12041, keptLen: 1800, path: '/x/abc.txt' });
    expect(ptr).toContain('12,041');
    expect(ptr).toContain('1,800');
    expect(ptr).toContain('10,241');         // between = 12041 - 1800
    expect(ptr).toContain('Read /x/abc.txt');
  });

  test('buildPointer never reports a negative between count', () => {
    const ptr = buildPointer({ originalLen: 100, keptLen: 250, path: '/x/y.txt' });
    expect(ptr).toContain('0 chars between');
  });

  // ---- GC -------------------------------------------------------------------

  test('gcHeadroom on a missing dir is a no-op', () => {
    expect(gcHeadroom(HEADROOM_DEFAULT_TTL_MS, home)).toEqual({ scanned: 0, removed: 0 });
  });

  test('gcHeadroom evicts files older than the TTL, keeps fresh ones', () => {
    const fresh = stashOriginal('fresh content here', home);
    const stale = stashOriginal('stale content here', home);

    // Age the stale file's mtime to 8 days ago.
    const eightDaysAgoSec = Math.floor((Date.now() - 8 * 24 * 60 * 60 * 1000) / 1000);
    utimesSync(stale.path, eightDaysAgoSec, eightDaysAgoSec);

    const res = gcHeadroom(HEADROOM_DEFAULT_TTL_MS, home);

    expect(res.scanned).toBe(2);
    expect(res.removed).toBe(1);
    expect(existsSync(stale.path)).toBe(false); // evicted
    expect(existsSync(fresh.path)).toBe(true);  // kept
  });

  test('gcHeadroom uses the injected clock (deterministic)', () => {
    const { path } = stashOriginal('time-travel', home);
    const realMtime = statSync(path).mtimeMs;

    // With "now" far in the future, even a just-written file is stale.
    const res = gcHeadroom(1000, home, realMtime + 5000);
    expect(res.removed).toBe(1);
    expect(existsSync(path)).toBe(false);
  });

  test('gcHeadroom ignores non-.txt files', () => {
    mkdirSync(getHeadroomDir(home), { recursive: true });
    // a stray lock/tmp file should not be counted or removed
    const stray = join(getHeadroomDir(home), 'something.lock');
    writeFileSync(stray, 'x');
    stashOriginal('real stash', home);

    const res = gcHeadroom(0, home, Date.now() + 1); // TTL 0 → evict all eligible
    expect(res.scanned).toBe(1);                      // only the .txt counted
    expect(existsSync(stray)).toBe(true);             // .lock untouched
  });
});
